.header { display: flex; justify-content: space-between; padding: 20px; background: #333; color: white; }
.nav a { color: white; text-decoration: none; margin: 0 10px; }
.main { padding: 40px 20px; }
h2 { font-size: 28px; margin-bottom: 20px; }
.cards { display: flex; gap: 16px; flex-wrap: wrap; }
.card { border: 1px solid #ddd; padding: 16px; width: 280px; }
.card img { width: 100%; height: 160px; object-fit: cover; }
.footer { text-align: center; padding: 20px; background: #333; color: white; }

:root {
  --color-primary: #2563eb;
  --color-text: #1f2937;
  --spacing-sm: 8px;
  --spacing-md: 16px;
  --spacing-lg: 32px;
}

* { margin: 0; padding: 0; box-sizing: border-box; }

body { font-family: 'Inter', sans-serif; color: var(--color-text); }

.header { padding: var(--spacing-md) var(--spacing-lg); }
.nav__list { display: flex; list-style: none; gap: var(--spacing-md); }
.nav__link { color: var(--color-primary); text-decoration: none; }
.nav__link:hover { text-decoration: underline; }

.hero { text-align: center; padding: var(--spacing-lg) 0; }
.hero__title { font-size: 2.5rem; margin-bottom: var(--spacing-md); }
.hero__image { border-radius: 50%; max-width: 100%; height: auto; }

.footer { text-align: center; padding: var(--spacing-md); background: #f3f4f6; }

@media (max-width: 768px) {
  .hero__title { font-size: 1.8rem; }
  .nav__list { flex-direction: column; }
}

@media (max-width: 480px) {
  .header { padding: var(--spacing-sm); }
}
